const API_BASE = 'http://localhost:5001/api';

async function fetchData(endpoint, params = {}) {
    const queryString = new URLSearchParams(params).toString();
    const url = `${API_BASE}${endpoint}${queryString ? '?' + queryString : ''}`;

    try {
        const response = await fetch(url);
        const data = await response.json();

        if (!data.success) {
            throw new Error(data.error || 'Unknown error');
        }

        return data;
    } catch (error) {
        console.error(`API Error (${endpoint}):`, error);
        throw error;
    }
}

// API 方法
const api = {
    health: () => fetchData('/health'),
    retention: (date) => fetchData('/retention', { date }),
    levels: (date) => fetchData('/levels', { date }),
    ads: (date) => fetchData('/ads', { date }),
    channels: (date) => fetchData('/channels', { date }),
    dashboard: (date) => fetchData('/dashboard', { date })
};

// Chart.js 配置
Chart.defaults.font.family = '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif';
Chart.defaults.color = '#666';

// 留存曲线图表
function createRetentionChart(canvasId, data) {
    const ctx = document.getElementById(canvasId).getContext('2d');

    const labels = data.map(d => d.date);
    const d1Data = data.map(d => d.d1_retention);
    const d7Data = data.map(d => d.d7_retention);
    const d30Data = data.map(d => d.d30_retention);

    return new Chart(ctx, {
        type: 'line',
        data: {
            labels: labels.reverse(),
            datasets: [
                {
                    label: '次日留存',
                    data: d1Data.reverse(),
                    borderColor: '#667eea',
                    backgroundColor: 'rgba(102, 126, 234, 0.1)',
                    tension: 0.4,
                    fill: true
                },
                {
                    label: '7日留存',
                    data: d7Data.reverse(),
                    borderColor: '#f093fb',
                    backgroundColor: 'rgba(240, 147, 251, 0.1)',
                    tension: 0.4,
                    fill: true
                },
                {
                    label: '30日留存',
                    data: d30Data.reverse(),
                    borderColor: '#4facfe',
                    backgroundColor: 'rgba(79, 172, 254, 0.1)',
                    tension: 0.4,
                    fill: true
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: {
                intersect: false,
                mode: 'index'
            },
            plugins: {
                legend: {
                    position: 'top'
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    max: 100,
                    ticks: {
                        callback: function(value) {
                            return value + '%';
                        }
                    }
                }
            }
        }
    });
}

// 关卡进度图表
function createLevelsChart(canvasId, data) {
    const ctx = document.getElementById(canvasId).getContext('2d');

    const labels = data.map(d => d.level_name || `关卡${d.level_id}`);
    const passRates = data.map(d => d.pass_rate);

    return new Chart(ctx, {
        type: 'bar',
        data: {
            labels: labels,
            datasets: [{
                label: '通过率',
                data: passRates,
                backgroundColor: passRates.map(rate => 
                    rate >= 70 ? '#4CAF50' : 
                    rate >= 40 ? '#FF9800' : '#f44336'
                ),
                borderRadius: 4
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    display: false
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    max: 100,
                    ticks: {
                        callback: function(value) {
                            return value + '%';
                        }
                    }
                }
            }
        }
    });
}

// 广告统计图表
function createAdsChart(canvasId, data) {
    const ctx = document.getElementById(canvasId).getContext('2d');

    const labels = data.map(d => d.ad_type);
    const views = data.map(d => d.total_views);
    const revenues = data.map(d => d.revenue);

    return new Chart(ctx, {
        type: 'bar',
        data: {
            labels: labels,
            datasets: [
                {
                    label: '观看次数',
                    data: views,
                    backgroundColor: 'rgba(102, 126, 234, 0.8)',
                    borderRadius: 4,
                    yAxisID: 'y'
                },
                {
                    label: '收入',
                    data: revenues,
                    backgroundColor: 'rgba(118, 75, 162, 0.8)',
                    borderRadius: 4,
                    yAxisID: 'y1'
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'top'
                }
            },
            scales: {
                y: {
                    type: 'linear',
                    display: true,
                    position: 'left',
                    title: {
                        display: true,
                        text: '观看次数'
                    }
                },
                y1: {
                    type: 'linear',
                    display: true,
                    position: 'right',
                    title: {
                        display: true,
                        text: '收入'
                    },
                    grid: {
                        drawOnChartArea: false
                    }
                }
            }
        }
    });
}

// 渠道分布图表
function createChannelsChart(canvasId, data) {
    const ctx = document.getElementById(canvasId).getContext('2d');

    const labels = data.map(d => d.channel_name);
    const values = data.map(d => d.new_users);

    const colors = [
        '#667eea', '#764ba2', '#f093fb', '#f5576c',
        '#4facfe', '#00f2fe', '#43e97b', '#38f9d7'
    ];

    return new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: labels,
            datasets: [{
                data: values,
                backgroundColor: colors.slice(0, values.length),
                borderWidth: 0
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'right'
                }
            }
        }
    });
}

// 全局变量
let charts = {};

// 格式化数字
function formatNumber(num) {
    if (num === null || num === undefined) return '-';
    return new Intl.NumberFormat('zh-CN').format(num);
}

// 格式化货币
function formatCurrency(num) {
    if (num === null || num === undefined) return '-';
    return '¥' + new Intl.NumberFormat('zh-CN', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
    }).format(num);
}

// 格式化百分比
function formatPercent(num) {
    if (num === null || num === undefined) return '-';
    return num.toFixed(2) + '%';
}

// 更新状态
function updateStatus(message) {
    document.getElementById('status').textContent = message;
}

// 获取选中的日期
function getSelectedDate() {
    return document.getElementById('dateInput').value;
}

// 加载仪表盘数据
async function loadDashboard() {
    try {
        const date = getSelectedDate();
        const data = await api.dashboard(date);

        if (data.data) {
            document.getElementById('newUsers').textContent = formatNumber(data.data.total_new_users);
            document.getElementById('activeUsers').textContent = formatNumber(data.data.total_active_users);
            document.getElementById('revenue').textContent = formatCurrency(data.data.total_revenue);
            document.getElementById('retention').textContent = formatPercent(data.data.avg_d1_retention);
        }
    } catch (error) {
        console.error('加载仪表盘失败:', error);
    }
}

// 加载留存数据
async function loadRetention() {
    try {
        const date = getSelectedDate();
        const data = await api.retention(date);

        if (charts.retention) {
            charts.retention.destroy();
        }

        charts.retention = createRetentionChart('retentionChart', data.data);
    } catch (error) {
        console.error('加载留存数据失败:', error);
        updateStatus('❌ 留存数据加载失败');
    }
}

// 加载关卡数据
async function loadLevels() {
    try {
        const date = getSelectedDate();
        const data = await api.levels(date);

        if (charts.levels) {
            charts.levels.destroy();
        }

        charts.levels = createLevelsChart('levelsChart', data.data);
    } catch (error) {
        console.error('加载关卡数据失败:', error);
        updateStatus('❌ 关卡数据加载失败');
    }
}

// 加载广告数据
async function loadAds() {
    try {
        const date = getSelectedDate();
        const data = await api.ads(date);

        if (charts.ads) {
            charts.ads.destroy();
        }

        charts.ads = createAdsChart('adsChart', data.data);
    } catch (error) {
        console.error('加载广告数据失败:', error);
        updateStatus('❌ 广告数据加载失败');
    }
}

// 加载渠道数据
async function loadChannels() {
    try {
        const date = getSelectedDate();
        const data = await api.channels(date);

        if (charts.channels) {
            charts.channels.destroy();
        }

        charts.channels = createChannelsChart('channelsChart', data.data);
    } catch (error) {
        console.error('加载渠道数据失败:', error);
        updateStatus('❌ 渠道数据加载失败');
    }
}

// 加载所有数据
async function loadAllData() {
    updateStatus('🔄 正在加载数据...');

    try {
        await Promise.all([
            loadDashboard(),
            loadRetention(),
            loadLevels(),
            loadAds(),
            loadChannels()
        ]);

        updateStatus('✅ 数据加载完成');
    } catch (error) {
        updateStatus('❌ 部分数据加载失败');
        console.error(error);
    }
}

// 页面加载完成后初始化
document.addEventListener('DOMContentLoaded', () => {
    // 设置默认日期为 2026-02-09
    document.getElementById('dateInput').value = '2026-02-09';

    // 加载数据
    loadAllData();
});
